async function createMxObj(entity) {
	return new Promise(function(resolve,reject) {
		mx.data.create({
			entity: entity,
			callback: function(obj) {
				resolve(obj);
			},
			error: function(e) {
				reject("Could not create object:", e);
			}
		}
		);
	});
}
