/**
 * @returns {Promise.<MxObject>}
 */
export async function JS_GetDataPoint() {
	// BEGIN USER CODE
	const obj = await createMxObj("EXCR_InlineSPC.SPCDataViewControl");
	const spcDataPointDetails = document.querySelector(".spcDataPointId").firstElementChild.value;
	
	const item = spcDataPointDetails.split("_");
	obj.set("DataPointNames", item[0]);
	obj.set("DataPointID", item[1]);
	obj.set("IsAnnotationRequired", item[2] = 'true' ? true : false);
	obj.set("SPCTxnDataID", document.querySelector(".spc-selected").firstElementChild.value);

	return obj;

	// END USER CODE
}
